-- @id: R1-chart-of-accounts
-- @gap: A1,A2,B1,B2
-- @risk: high
-- @type: sql
-- @description: Provision chart of accounts + accounting schema (A1), per-entity posting accounts (A2), the AD_ORG_TREE org hierarchy (B1) and the AD_TREENODE account-element tree (B2) for tenants onboarded before GL wiring existed
--
-- Hand-written, FROZEN migration. There is no generator.
--   * Source ids are written as @uuid_<srcid>@ labels. At apply time the runner
--     makes a temp copy and replaces every label with a fresh per-tenant id
--     (same label => same id, so intra-set FKs stay linked). A new tenant gets a
--     brand-new id set => ZERO cross-client references. The file on disk never changes.
--   * Tenant client/org are written as :client_id / :org_id and baked per tenant.
--   * The whole @apply runs in ONE transaction (runner wraps BEGIN/COMMIT); on
--     failure it rolls back and the chain halts for that tenant.
--   * Account-element tree: the element->tree pointer (step 0/1) AND the full
--     AD_TREENODE hierarchy (step 13, B2) are wired, so the chart is no longer flat.
--
-- Built by hand, once, from GOAdmin chart-of-accounts dumps and frozen here.
-- The org-specific (orphan) account-element tree
-- is excluded here, mirroring OnboardingDatasetNormalizer.AccountElementTreeFilter;
-- step 13 likewise drops the org-specific (ad_org_id<>'0') AD_TREENODE rows.

-- @check
-- Needs the fix when the tenant has NO accounting schema at all.
SELECT 1
FROM ad_client c
WHERE c.ad_client_id = :client_id
  AND NOT EXISTS (SELECT 1 FROM c_acctschema s WHERE s.ad_client_id = :client_id);

-- @apply
-- Tables are appended below in insertion order (parents first) as the GOAdmin
-- dumps are transformed:
--   0. AD_TREE              6. C_ACCTSCHEMA_TABLE
--   1. C_ELEMENT            7. C_VALIDCOMBINATION
--   2. C_ELEMENTVALUE       8. C_ACCTSCHEMA_GL
--   3. C_ELEMENTVALUE_TRL   9. C_ACCTSCHEMA_DEFAULT
--   4. C_ACCTSCHEMA        10. AD_ORG_ACCTSCHEMA
--   5. C_ACCTSCHEMA_ELEMENT 11. A2 per-entity posting accounts (*_acct).
--                              NOTE: the tax-due/tax-credit posting accounts
--                              (c_tax_acct) are NOT created here; they are owned
--                              by the R7-tax-accounts corrective, which joins the
--                              tenant's real schema(s) and so covers both this
--                              chart-creation case and tenants that already had a
--                              schema but no tax accounts.
--                          12. B1 AD_ORG_TREE hierarchy rows
--                          13. B2 AD_TREENODE account-element tree hierarchy
--
-- B1 note: this file's @check fires only when the tenant has NO accounting schema,
-- so step 12 reaches the same already-onboarded population that A1/A2 target (those
-- tenants lack BOTH the schema and the org tree). A tenant that somehow has a schema
-- but an empty AD_ORG_TREE would not be picked up here — handle that edge case with a
-- dedicated B1-only data-fix if it ever appears. Preventive twin:
-- OnboardingMarkOrgReadyService.provisionOrgTree.




-- ===========================================================================
-- 0. AD_TREE  (the account-element tree itself — inserted, NOT resolved by subquery,
--    because onboarding may never have created it). PKs become @uuid_<treeid>@ labels
--    so C_ELEMENT.ad_tree_id below links to the SAME fresh per-tenant id.
--    Source has ONE EV tree (D937..., ad_org_id='0', ad_table_id='188' = C_ElementValue).
--    Both C_ELEMENT rows link to it via @uuid_D937...@. ad_table_id '188' is a standard
--    AD id (not cross-tenant), kept as-is.
                     isactive, name, description, treetype, isallnodes, ad_table_id)
SELECT '@uuid_D937A98591DC4F6386C8130D350B17C7@', :client_id, '0', now(), '0', now(), '0',
       'Y', '@name_client@Client Element Value', '@name_client@Client Element Value', 'EV', 'Y', '188'
WHERE NOT EXISTS (
  SELECT 1 FROM ad_tree t
   WHERE t.ad_client_id = :client_id AND t.treetype = 'EV'
     AND t.name = '@name_client@Client Element Value'
);

-- ===========================================================================
-- 1. C_ELEMENT  (the account element / "natural account" tree container)
--   * Only the client-level element (source BB9B...) is provisioned. The org-specific
--     element (source 91D04..., 'GOOrg Account Tree', ad_org_id=GOOrg) is an orphan
--     tree and is intentionally NOT created, mirroring
--     OnboardingDatasetNormalizer.AccountElementTreeFilter.
--   * PK becomes a @uuid_<srcid>@ label (fresh per tenant, relationship-preserving).
--   * ad_tree_id links to the single inserted EV tree via @uuid_D937...@.
--   * ad_org_id is '0' (client-level).
--   * "GO" in the source name/description is the source client name -> @name_client@.

-- 1b. client-level element  (source BB9B...)
                       name, description, vformat, elementtype, isbalancing, isnaturalaccount, ad_tree_id,
                       add2tree_id, add1tree_id)
SELECT '@uuid_BB9B64C5B6534A40A36F7C0F45C2CC0B@', :client_id, '0', 'Y', now(), '0', now(), '0',
       'Arbol de cuentas @name_client@', '@name_client@Client Account', null, 'A', 'N', 'Y',
       '@uuid_D937A98591DC4F6386C8130D350B17C7@', null, null
WHERE NOT EXISTS (
  SELECT 1 FROM c_element e
   WHERE e.ad_client_id = :client_id AND e.name = 'Arbol de cuentas @name_client@'
);


--   2. C_ELEMENTVALUE


-- C_ELEMENTVALue_TRL



-- ===========================================================================
-- 4. C_ACCTSCHEMA   (accounting schema header; refs currency + C_ELEMENT)
--    PASTE RAW GOADMIN DUMP BELOW — will be label-transformed in place.
-- ===========================================================================


-- ===========================================================================
-- 5. C_ACCTSCHEMA_ELEMENT   (elements composing the schema; refs C_ACCTSCHEMA + C_ELEMENT)
--    PASTE RAW GOADMIN DUMP BELOW.
-- ===========================================================================


-- ===========================================================================
-- 6. C_ACCTSCHEMA_TABLE   (per-table accounting config; refs C_ACCTSCHEMA)
--    PASTE RAW GOADMIN DUMP BELOW.
-- ===========================================================================


-- ===========================================================================
-- 7. C_VALIDCOMBINATION   (account combinations; refs C_ELEMENTVALUE via account_id)
--    PASTE RAW GOADMIN DUMP BELOW.
-- ===========================================================================


-- ===========================================================================
-- 8. C_ACCTSCHEMA_GL   (GL defaults; *_acct cols -> C_VALIDCOMBINATION)
--    PASTE RAW GOADMIN DUMP BELOW.
-- ===========================================================================


