-- ===========================================================================
-- 11. A2 — PER-ENTITY POSTING ACCOUNTS (*_acct)
-- ===========================================================================
-- Gap A2: the posting engine (AcctServer) does NOT fall back to
-- c_acctschema_default to resolve the accounts of business-partner groups,
-- product categories, or individual BPs/products. It needs dedicated rows in
-- c_bp_group_acct / m_product_category_acct / c_bp_customer_acct /
-- c_bp_vendor_acct / m_product_acct, otherwise posting an invoice fails with
-- "Account Not Defined For ..." (or IllegalStateException for the per-BP/product
-- lookups). See onboarding-gaps-research-notes.md "Update 2026-06-09".
--
-- These run as the LAST step of the A1 @apply (same transaction) on purpose:
-- they SELECT the default accounts straight out of the c_acctschema_default and
-- c_validcombination rows created above for the SAME schema id
-- (@uuid_C06B100312FA48159DB36B9A4B461019@ — same token, so it resolves to the
-- same fresh per-tenant id). The *_acct ids themselves are NOT @uuid_<srcid>@
-- labels: the row count is dynamic (one per existing entity of the tenant), so
-- each PK is minted with get_uuid() at apply time (still zero cross-client refs).
--
-- Notes:
--   * ad_org_id is inherited from each source entity (g/c/bp/p.ad_org_id), NOT
--     forced to '0' — this mirrors GOClient, where the *_acct rows carry the org
--     of the entity they describe (mix of '0' and the operative org).
--   * Each INSERT is guarded by NOT EXISTS on (entity, schema) so it is safe to
--     re-run and never double-inserts.
--   * Defaults are read from the single c_acctschema_default row of this schema;
--     the NOT-NULL acct columns (v_liability_acct, writeoff_acct, p_revenue_acct,
--     p_expense_acct, p_cogs_acct) are always populated in the shipped default.
--   * Entities created AFTER onboarding still need their own *_acct rows at
--     creation time (separate concern, not covered by this one-shot corrective).
--
-- LOCKSTEP (two-front policy): the preventive twin of these five statements is
-- OnboardingAccountingWiringService.provisionEntityPostingAccounts in the
-- com.etendoerp.go module (runs at onboarding so NEW tenants never get the gap).
-- Keep the column lists, defaults source, org-inheritance and NOT EXISTS guards
-- identical in both files — edit one, mirror the other.

-- 11a. c_bp_group_acct — one row per business-partner group of the tenant.
  c_bp_group_acct_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby,
  c_bp_group_id, c_acctschema_id,
  c_receivable_acct, c_prepayment_acct,
  v_liability_acct, v_liability_services_acct, v_prepayment_acct,
  paydiscount_exp_acct, writeoff_acct, paydiscount_rev_acct, writeoff_rev_acct,
  notinvoicedreceivables_acct, notinvoicedrevenue_acct, notinvoicedreceipts_acct,
  unearnedrevenue_acct
)
SELECT
  get_uuid(), :client_id, g.ad_org_id, 'Y', now(), '0', now(), '0',
  g.c_bp_group_id, '@uuid_C06B100312FA48159DB36B9A4B461019@',
  d.c_receivable_acct, d.c_prepayment_acct,
  d.v_liability_acct, d.v_liability_services_acct, d.v_prepayment_acct,
  d.paydiscount_exp_acct, d.writeoff_acct, d.paydiscount_rev_acct, d.writeoff_rev_acct,
  d.notinvoicedreceivables_acct, d.notinvoicedrevenue_acct, d.notinvoicedreceipts_acct,
  d.unearnedrevenue_acct
FROM c_bp_group g, c_acctschema_default d
WHERE g.ad_client_id = :client_id
  AND d.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  AND NOT EXISTS (
    SELECT 1 FROM c_bp_group_acct a
     WHERE a.c_bp_group_id = g.c_bp_group_id
       AND a.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  );

-- 11b. m_product_category_acct — one row per product category of the tenant.
  m_product_category_acct_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby,
  m_product_category_id, c_acctschema_id,
  p_revenue_acct, p_expense_acct, p_cogs_acct, p_asset_acct,
  p_purchasepricevariance_acct, p_invoicepricevariance_acct,
  p_tradediscountrec_acct, p_tradediscountgrant_acct,
  p_revenue_return_acct, p_cogs_return_acct
)
SELECT
  get_uuid(), :client_id, c.ad_org_id, 'Y', now(), '0', now(), '0',
  c.m_product_category_id, '@uuid_C06B100312FA48159DB36B9A4B461019@',
  d.p_revenue_acct, d.p_expense_acct, d.p_cogs_acct, d.p_asset_acct,
  d.p_purchasepricevariance_acct, d.p_invoicepricevariance_acct,
  d.p_tradediscountrec_acct, d.p_tradediscountgrant_acct,
  d.p_revenue_return_acct, d.p_cogs_return_acct
FROM m_product_category c, c_acctschema_default d
WHERE c.ad_client_id = :client_id
  AND d.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  AND NOT EXISTS (
    SELECT 1 FROM m_product_category_acct a
     WHERE a.m_product_category_id = c.m_product_category_id
       AND a.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  );

-- 11c. c_bp_customer_acct — one row per customer business partner of the tenant.
  c_bp_customer_acct_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby,
  c_bpartner_id, c_acctschema_id, c_receivable_acct, c_prepayment_acct
)
SELECT
  get_uuid(), :client_id, bp.ad_org_id, 'Y', now(), '0', now(), '0',
  bp.c_bpartner_id, '@uuid_C06B100312FA48159DB36B9A4B461019@',
  d.c_receivable_acct, d.c_prepayment_acct
FROM c_bpartner bp, c_acctschema_default d
WHERE bp.ad_client_id = :client_id AND bp.iscustomer = 'Y'
  AND d.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  AND NOT EXISTS (
    SELECT 1 FROM c_bp_customer_acct a
     WHERE a.c_bpartner_id = bp.c_bpartner_id
       AND a.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  );

-- 11d. c_bp_vendor_acct — one row per vendor business partner of the tenant.
  c_bp_vendor_acct_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby,
  c_bpartner_id, c_acctschema_id, v_liability_acct, v_prepayment_acct
)
SELECT
  get_uuid(), :client_id, bp.ad_org_id, 'Y', now(), '0', now(), '0',
  bp.c_bpartner_id, '@uuid_C06B100312FA48159DB36B9A4B461019@',
  d.v_liability_acct, d.v_prepayment_acct
FROM c_bpartner bp, c_acctschema_default d
WHERE bp.ad_client_id = :client_id AND bp.isvendor = 'Y'
  AND d.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  AND NOT EXISTS (
    SELECT 1 FROM c_bp_vendor_acct a
     WHERE a.c_bpartner_id = bp.c_bpartner_id
       AND a.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  );

-- 11e. m_product_acct — one row per product of the tenant.
  m_product_acct_id, ad_client_id, ad_org_id, isactive, created, createdby, updated, updatedby,
  m_product_id, c_acctschema_id,
  p_revenue_acct, p_expense_acct, p_cogs_acct, p_asset_acct,
  p_purchasepricevariance_acct, p_invoicepricevariance_acct,
  p_tradediscountrec_acct, p_tradediscountgrant_acct,
  p_revenue_return_acct, p_cogs_return_acct
)
SELECT
  get_uuid(), :client_id, p.ad_org_id, 'Y', now(), '0', now(), '0',
  p.m_product_id, '@uuid_C06B100312FA48159DB36B9A4B461019@',
  d.p_revenue_acct, d.p_expense_acct, d.p_cogs_acct, d.p_asset_acct,
  d.p_purchasepricevariance_acct, d.p_invoicepricevariance_acct,
  d.p_tradediscountrec_acct, d.p_tradediscountgrant_acct,
  d.p_revenue_return_acct, d.p_cogs_return_acct
FROM m_product p, c_acctschema_default d
WHERE p.ad_client_id = :client_id
  AND d.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  AND NOT EXISTS (
    SELECT 1 FROM m_product_acct a
     WHERE a.m_product_id = p.m_product_id
       AND a.c_acctschema_id = '@uuid_C06B100312FA48159DB36B9A4B461019@'
  );

-- 11f. c_tax_acct — intentionally NOT here. The tax-due / tax-credit posting accounts are
-- created by the R7-tax-accounts corrective, which joins the tenant's real c_acctschema
-- row(s) and reads from the system tax catalog (C_TAX at ad_client_id = '0'). R7 runs after
-- R1 in the chain, so for a tenant that lands here (no schema) R7 sees the schema R1 just
-- created and fills in the tax accounts; for a tenant that already had a schema (R1 skipped),
-- R7 still fires on its own @check. One owner, both populations covered.

-- 12. AD_ORG_TREE (B1) — the precomputed org-hierarchy cache that AD_ISORGINCLUDED()
-- queries. Left empty for tenants onboarded before AD_Org_Ready ran (or whose run could
-- not see the new org), causing same-org documents to fail with "the organization of the
-- lines is different and does not depend on the organization associated with the header".
-- A flat onboarding org needs exactly two rows: a self-reference (levelno 1) and a child
-- of the root org '0' (levelno 2). Idempotent via NOT EXISTS, so re-applying never
-- double-inserts. Lockstep twin: OnboardingMarkOrgReadyService.provisionOrgTree.

-- 12a. Self-reference (the org includes itself), levelno 1.
  ad_org_tree_id, ad_client_id, isactive, created, createdby, updated, updatedby,
  ad_org_id, ad_parent_org_id, levelno
)
SELECT get_uuid(), :client_id, 'Y', now(), '0', now(), '0', :org_id, :org_id, 1
WHERE NOT EXISTS (
  SELECT 1 FROM ad_org_tree t
   WHERE t.ad_org_id = :org_id AND t.ad_parent_org_id = :org_id
);

-- 12b. Child of the root org '*' ('0'), levelno 2.
  ad_org_tree_id, ad_client_id, isactive, created, createdby, updated, updatedby,
  ad_org_id, ad_parent_org_id, levelno
)
SELECT get_uuid(), :client_id, 'Y', now(), '0', now(), '0', :org_id, '0', 2
WHERE NOT EXISTS (
  SELECT 1 FROM ad_org_tree t
   WHERE t.ad_org_id = :org_id AND t.ad_parent_org_id = '0'
);

-- ===========================================================================
-- 13. AD_TREENODE (account-element EV tree hierarchy)
-- ===========================================================================
-- The chart of accounts above is loaded FLAT: C_ELEMENT points at the tenant's EV
-- tree (step 0, '@uuid_D937A98591DC4F6386C8130D350B17C7@') but no AD_TREENODE rows
-- place each C_ELEMENTVALUE under its parent. Result: the ~1790 accounts hang loose
-- off the root, summary accounts (issummary='Y') do not roll up their children, and
-- tree-walking reports (Balance/P&L) show nothing under summaries. Posting (AcctServer)
-- does not need the tree, which is why this surfaced only in the account window/reports.
--
-- This step rebuilds the EV-tree hierarchy. Each AD_TREENODE row is transformed from the
-- raw GOAdmin dump with the SAME relationship-preserving placeholder scheme as the rest
-- of this file:
--   * ad_tree_id   -> '@uuid_D937A98591DC4F6386C8130D350B17C7@'  (the tenant EV tree, step 0)
--   * node_id      -> '@uuid_<c_elementvalue_id>@'               (label already used above)
--   * parent_id    -> '@uuid_<parent_c_elementvalue_id>@', or '0' for root nodes
--   * ad_treenode_id -> get_uuid() (fresh per tenant)
--   * ad_client_id -> :client_id, ad_org_id -> '0'
-- Plain INSERT ... VALUES like the rest of the chart (steps 1-3): the file's @check
-- ("tenant has NO accounting schema") gates the whole apply, so it never re-runs for a
-- tenant that already has the chart/tree.
-- Preventive twin: OnboardingAccountingWiringService.wireAccountElementTree.
--

-- 13a. One node per account (1790 rows). org-specific orphan-tree nodes
-- (ad_org_id='61849243BE89460EB70866880A545D50') and any node not backing a
-- kept C_ELEMENTVALUE are dropped, so every node resolves; 4 roots (parent_id='0').

